x_snc_airop_check_definition.check_script:
(function(){
var sa=new GlideRecord("sys_store_app");
sa.addQuery("scope","sn_tprm_genai");
sa.setLimit(1);sa.query();
if(sa.next())return{status:"ready",actualValue:"v"+sa.getValue("version"),finding:"Now Assist for TPRM is installed."};
return{status:"value_blocker",actualValue:"Not installed",finding:"Now Assist for TPRM (sn_tprm_gen_ai) is not installed."};
})()
